import { PathChangeRequest } from './path-change-request';
/**
 * Handler function for changing the app's URL path.
 *
 * With a custom path change handler implementation it is possible to change the app route using ie. built-in routing library features without reloading the app document.
 *
 * @param {PathChangeRequest} pathChangeRequest Path change request object with a new path
 * @returns {void}
 * @ignore
 */
export type PathChangeHandler = ((pathChangeRequest: PathChangeRequest) => void) | null;
